    79→  }
    80→}
    81→```
    82→
    83→### 1.2 Value Object: `BoundingBox`
    84→
    85→```ts
    86→// packages/core/valueObjects/BoundingBox.ts
    87→export interface BoundingBox {
    88→  x: number; y: number; width: number; height: number;
    89→  intersects(other: BoundingBox): boolean;
    90→}
    91→
    92→export const BoundingBox = {
    93→  intersects(a: BoundingBox, b: BoundingBox): boolean {
    94→    return (
    95→      a.x < b.x + b.width &&
    96→      a.x + a.width > b.x &&
    97→      a.y < b.y + b.height &&
    98→      a.y + a.height > b.y
    99→    );
   100→  }
   101→};
   102→```
   103→
   104→---
   105→
   106→## 2. Use-Case Layer (`packages/usecases`)
   107→
   108→### 2.1 Interactor: `CreateNode`
   109→
   110→```ts
   111→// packages/usecases/CreateNode.ts
   112→import { NodeFactory } from '../core/factories';
   113→import { ICanvasRepository } from './ports/ICanvasRepository';
   114→import { EventBus } from '../core/EventBus';
   115→
   116→export interface CreateNodeCommand {
   117→  canvasId: string;
   118→  type: string;
   119→  initialContent?: unknown;
   120→  position: { x: number; y: number };
   121→}
   122→
   123→/**
   124→ * Use-case for creating a node. Note that it is framework-agnostic and only
   125→ * depends on abstraction interfaces (`ICanvasRepository`, `EventBus`).
   126→ */
   127→export class CreateNode {
   128→  constructor(
   129→    private readonly repo: ICanvasRepository,
   130→    private readonly eventBus: EventBus
   131→  ) {}
   132→
   133→  async execute(cmd: CreateNodeCommand): Promise<void> {
   134→    const canvas = await this.repo.findById(cmd.canvasId);
   135→    const node = NodeFactory.create({
   136→      type: cmd.type,
   137→      position: cmd.position,
   138→      content: cmd.initialContent
   139→    });
   140→
   141→    canvas.addNode(node);
   142→
   143→    await this.repo.save(canvas);
   144→    this.eventBus.publish(canvas.toDomainEventStream());
   145→  }
   146→}
   147→```
   148→
   149→---
   150→
   151→## 3. Adapter Layer
   152→
   153→### 3.1 Electron Renderer → ViewModel
   154→
   155→```ts
   156→// packages/desktop/viewmodels/CanvasVM.ts
   157→import { BehaviorSubject } from 'rxjs';
   158→import { CreateNode } from '../../usecases';
   159→import { ipcRenderer } from 'electron';
   160→
   161→export class CanvasVM {
   162→  private readonly state$ = new BehaviorSubject<CanvasState>(initialState);
   163→
   164→  constructor(private readonly createNodeUC: CreateNode) {
   165→    ipcRenderer.on('menu:create-node', (_, payload) => this.createNode(payload));
   166→  }
   167→
   168→  getState() { return this.state$.asObservable(); }
   169→
   170→  async createNode(payload: { type: string; x: number; y: number }) {
   171→    try {
   172→      await this.createNodeUC.execute({
   173→        canvasId: this.state$.value.activeCanvasId,
   174→        type: payload.type,
   175→        position: { x: payload.x, y: payload.y }
   176→      });
   177→    } catch (err) {
   178→      console.error('[CanvasVM] createNode failed', err);
   179→      // TODO: route to notifications store
   180→    }
   181→  }
   182→}
   183→```
   184→
   185→---
   186→
   187→## 4. Plugin Runtime
   188→
   189→Plugins are Node-isolated CommonJS/ESM modules loaded at runtime.  
   190→They *must* export a `PalettePlugin` that adheres to the following interface:
   191→
   192→```ts
   193→// packages/plugin-sdk/index.ts
   194→export interface PalettePlugin {
   195→  id: string;
   196→  displayName: string;
   197→  activate(context: PluginContext): void;
   198→  deactivate?(): void;
   199→}
   200→
   201→export interface PluginContext {
   202→  logger: Logger;
   203→  registerNodeType(definition: NodeTypeDefinition): void;
   204→  registerTheme(theme: Theme): void;
   205→  commands: CommandRegistry;
   206→}
   207→```
   208→
   209→### 4.1 Example Plugin `@palettes/sketchNode`
   210→
   211→```ts
   212→// plugins/sketch-node/index.ts
   213→import { PalettePlugin } from 'paletteflow/plugin-sdk';
   214→
   215→const SketchPlugin: PalettePlugin = {
   216→  id: 'com.paletteflow.sketch-node',
   217→  displayName: 'Sketch Node',
   218→  activate({ registerNodeType, logger }) {
   219→    logger.info('Activating Sketch Node Plugin');
   220→    registerNodeType({
   221→      id: 'sketch',
   222→      title: 'Sketch',
   223→      component: async () => import('./SketchNodeRenderer'),
   224→      initialContent: { paths: [] }
   225→    });
   226→  }
   227→};
   228→
   229→export = SketchPlugin;
   230→```
   231→
   232→Plugins are sandboxed using the [`vm2`](https://github.com/patriksimek/vm2) library, preventing malicious file-system access while still giving useful APIs.
   233→
   234→---
   235→
   236→## 5. State Machine (Node Lifecycle)
   237→
   238→Each node has an internal lifecycle expressed as a small `xstate` machine:
   239→
   240→```ts
   241→// packages/core/statemachines/nodeLifecycle.ts
   242→import { createMachine, assign } from 'xstate';
   243→
   244→interface NodeCtx { dirty: boolean }
   245→type NodeEvt = { type: 'EDIT' } | { type: 'SAVE_SUCCESS' } | { type: 'SAVE_FAILURE', error: Error };
   246→
   247→export const nodeLifecycleMachine = createMachine<NodeCtx, NodeEvt>({
   248→  id: 'node',
   249→  initial: 'clean',
   250→  context: { dirty: false },
   251→  states: {
   252→    clean: {
   253→      on: { EDIT: { target: 'dirty', actions: assign({ dirty: _ => true }) } }
   254→    },
   255→    dirty: {
   256→      invoke: {
   257→        src: 'saveNode',
   258→        onDone: { target: 'clean', actions: assign({ dirty: _ => false }) },
   259→        onError: { target: 'error' }
   260→      }
   261→    },
   262→    error: {
   263→      entry: ['notifyError'],
   264→      on: { EDIT: 'dirty' }
   265→    }
   266→  }
   267→});
   268→```
   269→
   270→---
   271→
   272→## 6. Event Bus & Observer Pattern
   273→
   274→The Event Bus is a thin RxJS subject that bridges domain events to interested adapters:
   275→
   276→```ts
   277→// packages/core/EventBus.ts
   278→import { Subject } from 'rxjs';
   279→
   280→export type DomainEvent =
   281→  | { type: 'NodeCreated'; canvasId: string; nodeId: string }
   282→  | { type: 'ThemeApplied'; workspaceId: string; themeId: string };
   283→
   284→export class EventBus {
   285→  private readonly events$ = new Subject<DomainEvent>();
   286→
   287→  publish(events: DomainEvent | DomainEvent[]) {
   288→    (Array.isArray(events) ? events : [events]).forEach(evt => this.events$.next(evt));
   289→  }
   290→
   291→  subscribe(listener: (evt: DomainEvent) => void) {
   292→    return this.events$.subscribe(listener);
   293→  }
   294→}
   295→```
   296→
   297→`CrashReporter`, `AutoUpdater`, and `Analytics` are all *observers* that attach to the `EventBus` and perform side-effects such as telemetry or emergency persistence on crash.
   298→
   299→---
   300→
   301→## 7. Error Strategy
   302→
   303→Errors **never** leak across layers unwrapped.  
   304→We employ a unified `Result<T, E>` type with exhaustive switching in callers.
   305→
   306→```ts
   307→// packages/core/shared/Result.ts
   308→export type Result<T, E extends Error = Error> =
   309→  | { ok: true; value: T }
   310→  | { ok: false; error: E };
   311→
   312→export const Result = {
   313→  ok<T>(value: T): Result<T, never> { return { ok: true, value }; },
   314→  fail<E extends Error>(error: E): Result<never, E> { return { ok: false, error }; }
   315→};
   316→```
   317→
   318→---
   319→
   320→## 8. Build Pipeline
   321→
   322→1. `pnpm monorepo` workspace → shares versions, scripts, lockfile.
   323→2. `esbuild` for *core* & *use-cases* (fast, tree-shakable).
   324→3. `vite` for renderer; `electron-builder` for desktop packaging.
   325→4. End-to-end tests via Playwright using the [Electron](https://playwright.dev/docs/api/class-electron) driver.
   326→5. Sentry wraps the Electron main and renderer to capture uncaught exceptions.
   327→
   328→---
   329→
   330→## 9. Key Design Decisions
   331→
   332→• Serializable domain events enable *time-travel debugging* and potentially multiplayer sync  
   333→• Plugin system purposely kept **non-eval**; each plugin runs in `vm2` or a WebAssembly sandbox  
   334→• All state lives in “view-models” → React components are *pure views*  
   335→• No “service locator” — dependencies passed via constructors for testability  
   336→• Data persistence uses **executable JSON** (`.pflow.jsonc`) that can be inspected & version-controlled  
   337→
   338→---
   339→
   340→## 10. Contribution Workflow
   341→
   342→```
   343→fork → feature-branch → `pnpm test && pnpm lint` → PR → code-review (2 approvals) → squash merge
   344→```
   345→
   346→Add tests next to code (`*.spec.ts`), prefer property-based strategies for entities’ invariants.
   347→
   348→Happy hacking 💜
   349→```

