    26→import { Workspace } from '../../core/domain/entities/Workspace';
    27→import { IWorkspaceRepository } from '../../core/domain/repositories/IWorkspaceRepository';
    28→import { WorkspaceId } from '../../core/domain/value-objects/WorkspaceId';
    29→import { DomainError } from '../../core/domain/errors/DomainError';
    30→import { Logger } from '../../shared/infra/Logger';
    31→
    32→const gzip = promisify(_gzip);
    33→const gunzip = promisify(_gunzip);
    34→
    35→const WORKSPACE_FILE_NAME = 'workspace.pfws';  // gzipped JSON
    36→const MANIFEST_FILE_NAME = 'manifest.json';    // plain JSON
    37→
    38→/**
    39→ * Shape of the cached manifest.  Kept intentionally flat.
    40→ */
    41→interface WorkspaceManifest {
    42→  id: string;
    43→  name: string;
    44→  createdAt: string;
    45→  updatedAt: string;
    46→  themeId?: string;
    47→}
    48→
    49→/**
    50→ * Returned by FileSystemWorkspaceRepository.listWorkspaces so that callers
    51→ * don't have to inflate the whole Workspace object if they only need a list
    52→ * for a picker dialog.
    53→ */
