    55→  id: string;
    56→  name: string;
    57→  path: string;
    58→  updatedAt: Date;
    59→}
    60→
    61→/**
    62→ * Custom infrastructure-level errors
    63→ */
    64→export class WorkspaceNotFoundError extends DomainError {}
    65→export class WorkspacePersistenceError extends DomainError {}
    66→export class WorkspaceCorruptedError extends DomainError {}
    67→
    68→/**
    69→ * A production-ready implementation of the WorkspaceRepository port.
    70→ *
    71→ * Responsibilities
    72→ *  • Translate Workspace aggregates <-> on-disk representation.
    73→ *  • Guarantee atomic writes (via write-to-tmp-then-rename).
    74→ *  • Emit events when anything noteworthy happens so that live preview windows
    75→ *    can hot-reload.
    76→ *  • Basic optimistic locking to avoid clobbering concurrent saves.
    77→ */
    78→export class FileSystemWorkspaceRepository
    79→  extends EventEmitter
    80→  implements IWorkspaceRepository
    81→{
    82→  constructor(
    83→    private readonly rootDir: string,
    84→    private readonly logger: Logger = new Logger('FileSystemWorkspaceRepository'),
