    89→  // --------------------------------------------------------------------- //
    90→  //  IWorkspaceRepository implementation
    91→  // --------------------------------------------------------------------- //
    92→
    93→  /**
    94→   * Loads a Workspace aggregate from the given directory.
    95→   *
    96→   * @throws WorkspaceNotFoundError   if path doesn't exist
    97→   * @throws WorkspaceCorruptedError  if file cannot be parsed / verified
    98→   */
    99→  async load(workspacePathOrId: string): Promise<Workspace> {
   100→    const dir = this.resolveWorkspaceDir(workspacePathOrId);
   101→    const dataPath = path.join(dir, WORKSPACE_FILE_NAME);
   102→
   103→    try {
   104→      await fs.access(dataPath, fsConstants.F_OK);
   105→    } catch {
   106→      throw new WorkspaceNotFoundError(
   107→        `Workspace not found at ${dataPath}`,
   108→      );
   109→    }
