   126→  /**
   127→   * Saves a Workspace aggregate.  Will create the containing directory if it
   128→   * doesn't exist yet.  To guarantee that we never leave half-written files,
   129→   * the method writes to `${file}.tmp` first and then `rename`s it over the
   130→   * previous version (atomic on most modern file-systems).
   131→   */
   132→  async save(workspace: Workspace): Promise<void> {
   133→    const dir = this.resolveWorkspaceDir(workspace.id.value);
   134→    await fs.mkdir(dir, { recursive: true });
   135→
