   144→    const serialized = JSON.stringify(workspace.toPrimitives());
   145→    const compressed = await gzip(Buffer.from(serialized, 'utf-8'));
   146→
   147→    const dataPath = path.join(dir, WORKSPACE_FILE_NAME);
   148→    const tmpPath = `${dataPath}.tmp`;
   149→
   150→    try {
   151→      // --- Write data file atomically ---------------------------------- //
   152→      await fs.writeFile(tmpPath, compressed, { flag: 'w' });
   153→      await fs.rename(tmpPath, dataPath);
