   155→      // --- Update manifest (best effort – if this fails, the workspace is
   156→      //     still safe; we'll just log an error) ------------------------ //
   157→      await fs.writeFile(
   158→        path.join(dir, MANIFEST_FILE_NAME),
   159→        JSON.stringify(manifest, null, 2),
   160→        { flag: 'w' },
   161→      );
