     2→/***************************************************************************************************
     3→ * File:    src/core/application/use-cases/node/UpdateNodePosition.ts
     4→ * Project: PaletteFlow Studio (desktop_productivity)
     5→ * Author:  PaletteFlow Core Team
     6→ *
     7→ * Description:
     8→ *  Use-case that updates the coordinates of a Node on a Canvas.  While it looks deceptively simple,
     9→ *  moving a node has a ripple-effect throughout the system: links must be re-routed, view-models
    10→ *  need to animate, plugins may veto the move, and collaboration back-channels need deltas
    11→ *  broadcasted.  This interactor isolates those concerns behind clean architecture boundaries.
    12→ *
    13→ *  – Validates input and entity invariants
    14→ *  – Executes inside an ACID-like transaction provided by the Persistence layer
    15→ *  – Notifies the domain event-bus so observers (view, plugin-SDK, collab service) react
    16→ *  – Exposes a Result<E, A> functional style API for ergonomic error handling up-stack
    17→ ***************************************************************************************************/
    18→
    19→import { injectable, inject } from "tsyringe";
    20→import { NodeRepository } from "../../ports/NodeRepository";
    21→import { CanvasRepository } from "../../ports/CanvasRepository";
    22→import { DomainEventBus } from "../../ports/DomainEventBus";
    23→import { PluginHost } from "../../ports/PluginHost";
    24→import { TransactionManager } from "../../ports/TransactionManager";
    25→import { NodeId, CanvasId, UserId } from "../../../domain/value-objects";
    26→import { Node } from "../../../domain/entities/Node";
    27→import { NodePositionUpdated } from "../../../domain/events/NodePositionUpdated";
    28→
    29→/* -------------------------------------------------------------------------- */
    30→/*                                  Result<E,A>                               */
    31→/* -------------------------------------------------------------------------- */
    32→
    33→type Ok<A>    = { ok: true;  value: A };
    34→type Err<E>   = { ok: false; error: E };
    35→export type Result<E, A> = Ok<A> | Err<E>;
    36→
    37→const ok   = <A>(value: A): Ok<A>      => ({ ok: true,  value });
    38→const err  = <E>(error: E): Err<E>     => ({ ok: false, error });
    39→
    40→/* -------------------------------------------------------------------------- */
    41→/*                               Error Contracts                              */
    42→/* -------------------------------------------------------------------------- */
    43→
    44→export enum UpdateNodePositionErrorKind {
    45→    INVALID_INPUT            = "INVALID_INPUT",
    46→    NODE_NOT_FOUND           = "NODE_NOT_FOUND",
    47→    CANVAS_NOT_FOUND         = "CANVAS_NOT_FOUND",
    48→    NODE_NOT_IN_CANVAS       = "NODE_NOT_IN_CANVAS",
    49→    PLUGIN_REJECTED_POSITION = "PLUGIN_REJECTED_POSITION",
    50→    PERSISTENCE_ERROR        = "PERSISTENCE_ERROR"
    51→}
    52→
    53→export class UpdateNodePositionError extends Error {
    54→    constructor(
    55→        public readonly kind: UpdateNodePositionErrorKind,
    56→        details?: string
    57→    ) {
    58→        super(`[UpdateNodePosition] ${kind}${details ? ` – ${details}` : ""}`);
    59→        this.name = "UpdateNodePositionError";
    60→    }
    61→}
    62→
    63→/* -------------------------------------------------------------------------- */
    64→/*                                Input DTO                                   */
    65→/* -------------------------------------------------------------------------- */
    66→
    67→export interface UpdateNodePositionDTO {
    68→    canvasId   : CanvasId;
    69→    nodeId     : NodeId;
    70→    x          : number;
    71→    y          : number;
    72→    initiatedBy: UserId;
    73→}
    74→
    75→/* -------------------------------------------------------------------------- */
    76→/*                            UpdateNodePosition                              */
    77→/* -------------------------------------------------------------------------- */
    78→
    79→@injectable()
    80→export class UpdateNodePosition {
    81→    constructor(
    82→        @inject("NodeRepository")
    83→        private readonly nodeRepo: NodeRepository,
    84→
    85→        @inject("CanvasRepository")
    86→        private readonly canvasRepo: CanvasRepository,
    87→
    88→        @inject("DomainEventBus")
    89→        private readonly eventBus: DomainEventBus,
    90→
    91→        @inject("PluginHost")
    92→        private readonly pluginHost: PluginHost,
    93→
    94→        @inject("TransactionManager")
    95→        private readonly tx: TransactionManager
    96→    ) {}
    97→
    98→    /**
    99→     * Executes the use-case.
   100→     *
   101→     * PRE-CONDITIONS
   102→     *  – nodeId and canvasId are UUIDv4 strings
   103→     *  – x and y are finite numbers
   104→     * POST-CONDITIONS
   105→     *  – Node’s position is updated in storage
   106→     *  – Domain event is published
   107→     */
   108→    async execute(dto: UpdateNodePositionDTO): Promise<Result<UpdateNodePositionError, void>> {
   109→        /* ------------------------------ Validation ------------------------------ */
   110→        if (!this.isFiniteCoordinate(dto.x, dto.y)) {
   111→            return err(new UpdateNodePositionError(
   112→                UpdateNodePositionErrorKind.INVALID_INPUT,
   113→                `Coordinates must be finite numbers. Received (${dto.x}, ${dto.y})`
   114→            ));
   115→        }
   116→
   117→        /* ----------------------- Fetch Canvas + Node ------------------------ */
   118→        const canvas = await this.canvasRepo.findById(dto.canvasId);
   119→        if (!canvas) {
   120→            return err(new UpdateNodePositionError(
   121→                UpdateNodePositionErrorKind.CANVAS_NOT_FOUND,
   122→                `Canvas <${dto.canvasId}> does not exist`
   123→            ));
   124→        }
   125→
   126→        const node = await this.nodeRepo.findById(dto.nodeId);
   127→        if (!node) {
   128→            return err(new UpdateNodePositionError(
   129→                UpdateNodePositionErrorKind.NODE_NOT_FOUND,
   130→                `Node <${dto.nodeId}> does not exist`
   131→            ));
   132→        }
   133→
   134→        if (!canvas.containsNode(node.id)) {
   135→            return err(new UpdateNodePositionError(
   136→                UpdateNodePositionErrorKind.NODE_NOT_IN_CANVAS,
   137→                `Node <${dto.nodeId}> is not part of Canvas <${dto.canvasId}>`
   138→            ));
   139→        }
   140→
   141→        /* ------------------ Plugin‐level veto / transformation ------------------ */
   142→        const pluginDisposition = await this.pluginHost.hooks.beforeNodeMove.reduce(
   143→            async (incomingPosition, hook) => hook(node, await incomingPosition),
   144→            Promise.resolve({ x: dto.x, y: dto.y })
   145→        );
   146→
   147→        if (pluginDisposition === false) {
   148→            return err(new UpdateNodePositionError(
   149→                UpdateNodePositionErrorKind.PLUGIN_REJECTED_POSITION,
   150→                `A plugin vetoed the node move.`
   151→            ));
   152→        }
   153→
   154→        /* -------------------- Execute inside a transaction -------------------- */
   155→        try {
   156→            await this.tx.runInTransaction(async () => {
   157→                const oldPosition = { ...node.position };
   158→                node.moveTo(pluginDisposition.x, pluginDisposition.y);
   159→                await this.nodeRepo.save(node);
   160→
   161→                /* --------- Domain event lets observers (UI, collab) react -------- */
   162→                await this.eventBus.publish(new NodePositionUpdated({
   163→                    nodeId      : node.id,
   164→                    canvasId    : dto.canvasId,
   165→                    oldPosition,
   166→                    newPosition : { ...node.position },
   167→                    initiatedBy : dto.initiatedBy
   168→                }));
   169→            });
   170→        } catch (e) {
   171→            return err(new UpdateNodePositionError(
   172→                UpdateNodePositionErrorKind.PERSISTENCE_ERROR,
   173→                (e as Error).message
   174→            ));
   175→        }
   176→
   177→        /* ------------------------------ Epilogue ----------------------------- */
   178→        await this.pluginHost.hooks.afterNodeMove.forEach(hook =>
   179→            hook(node, { x: node.position.x, y: node.position.y })
   180→        );
   181→
   182→        return ok(undefined);
   183→    }
   184→
   185→    /* ---------------------------------------------------------------------- */
   186→    /*                                Helpers                                 */
   187→    /* ---------------------------------------------------------------------- */
   188→
   189→    private isFiniteCoordinate(x: number, y: number): boolean {
   190→        return Number.isFinite(x) && Number.isFinite(y);
   191→    }
   192→}
