     2→/**************************************************************************************************
     3→ * PaletteFlow Studio – IPC Channel Definitions (Main Process)
     4→ * -----------------------------------------------------------------------------------------------
     5→ * This module centralises every production-grade IPC channel that the main process exposes to
     6→ * renderer windows and plugins.  All traffic is strongly typed and routed through a single
     7→ * registry, enabling runtime auditing, hot-reloading of plugin handlers, granular permission
     8→ * checks, and test-time mocking.
     9→ *
    10→ * NOTE:  Only code running in the Electron main context should import this file.
    11→ *************************************************************************************************/
    12→
    13→import {
    14→  BrowserWindow,
    15→  IpcMainInvokeEvent,
    16→  IpcMainEvent,
    17→  WebContents,
    18→  ipcMain,
    19→} from 'electron';
    20→import { autoUpdater } from 'electron-updater';
    21→import { v4 as uuidv4 } from 'uuid';
    22→
    23→import { SettingsService } from '../services/settings-service';
    24→import { CrashReporterService } from '../services/crash-reporter-service';
    25→import { WorkspaceExportService } from '../services/workspace-export-service';
    26→import { PluginService } from '../services/plugin-service';
    27→import { WindowManager } from '../windows/window-manager';
    28→
    29→/* -------------------------------------------------------------------------------------------------
    30→ * Type-Safe Channel Map
    31→ * -----------------------------------------------------------------------------------------------*/
    32→
    33→export const Channels = {
    34→  SETTINGS_GET: 'settings:get',
    35→  SETTINGS_SET: 'settings:set',
    36→  AUTOUPDATE_CHECK: 'autoupdate:check',
    37→  CRASH_SUBMIT: 'crash:submit',
    38→  WORKSPACE_EXPORT: 'workspace:export',
    39→  WINDOW_NEW: 'window:new',
    40→  PLUGIN_INVOKE: 'plugin:invoke',
    41→
    42→  /* Broadcast-only events */
    43→  AUTOUPDATE_STATE: 'autoupdate:state',
    44→} as const;
    45→
    46→type ValueOf<T> = T[keyof T];
    47→export type Channel = ValueOf<typeof Channels>;
    48→
    49→/* ---------------------------------- Payload Contracts -----------------------------------------*/
    50→
    51→/* Settings ------------------------------------------------------------*/
    52→export interface SettingsGetRequest {
    53→  key?: string; // if omitted, return full settings object
    54→}
    55→export type SettingsGetResponse = unknown;
    56→
    57→export interface SettingsSetRequest {
    58→  key: string;
    59→  value: unknown;
    60→}
    61→export type SettingsSetResponse = void;
    62→
    63→/* Auto-Update ---------------------------------------------------------*/
    64→export type AutoUpdateCheckResponse =
    65→  | { status: 'up-to-date' }
    66→  | { status: 'available'; version: string };
    67→
    68→export type AutoUpdateStateEvent =
    69→  | { phase: 'checking' }
    70→  | { phase: 'downloading'; progress: number }
    71→  | { phase: 'downloaded'; version: string }
    72→  | { phase: 'error'; reason: string };
    73→
    74→/* Crash Reporting -----------------------------------------------------*/
    75→export interface CrashSubmitRequest {
    76→  reason: string;
    77→  details?: Record<string, unknown>;
    78→}
    79→export interface CrashSubmitResponse {
    80→  reportId: string;
    81→}
    82→
    83→/* Workspace Export ----------------------------------------------------*/
    84→export interface WorkspaceExportRequest {
    85→  workspaceId: string;
    86→  format: 'zip' | 'json';
    87→}
    88→export interface WorkspaceExportResponse {
    89→  filePath: string;
    90→}
    91→
    92→/* Window Management ---------------------------------------------------*/
    93→export interface WindowNewRequest {
    94→  workspaceId?: string;
    95→}
    96→export interface WindowNewResponse {
    97→  windowId: number;
    98→}
    99→
   100→/* Plugin Invocation ---------------------------------------------------*/
   101→export interface PluginInvokeRequest {
   102→  pluginId: string;
   103→  command: string;
   104→  args: unknown[];
   105→}
   106→export type PluginInvokeResponse = unknown;
   107→
   108→/* Generic Invocation Handler ------------------------------------------*/
   109→type Handler<Req, Res> = (
   110→  event: IpcMainInvokeEvent,
   111→  payload: Req,
   112→) => Promise<Res> | Res;
   113→
   114→/* -------------------------------------------------------------------------------------------------
   115→ * IPC Registry
   116→ * -----------------------------------------------------------------------------------------------*/
   117→
   118→export class IpcRegistry {
   119→  private registeredHandlers = new Map<Channel, (...args: any[]) => any>();
   120→
   121→  constructor(
   122→    private readonly settings: SettingsService,
   123→    private readonly crashReporter: CrashReporterService,
   124→    private readonly workspaceExporter: WorkspaceExportService,
   125→    private readonly pluginService: PluginService,
   126→    private readonly windowManager: WindowManager,
   127→  ) {}
   128→
   129→  /* ------------------------ Public life-cycle ------------------------*/
   130→
   131→  initialise(): void {
   132→    this.register(Channels.SETTINGS_GET, this.onSettingsGet);
   133→    this.register(Channels.SETTINGS_SET, this.onSettingsSet);
   134→    this.register(Channels.AUTOUPDATE_CHECK, this.onAutoupdateCheck);
   135→    this.register(Channels.CRASH_SUBMIT, this.onCrashSubmit);
   136→    this.register(Channels.WORKSPACE_EXPORT, this.onWorkspaceExport);
   137→    this.register(Channels.WINDOW_NEW, this.onWindowNew);
   138→    this.register(Channels.PLUGIN_INVOKE, this.onPluginInvoke);
   139→
   140→    this.wireAutoupdateEvents();
   141→
   142→    /* Expose registration for plugins */
   143→    this.pluginService.onRegisterIpcHandler((channel, handler) => {
   144→      this.dynamicRegister(channel, handler);
   145→    });
   146→  }
   147→
   148→  dispose(): void {
   149→    for (const [channel, handler] of this.registeredHandlers) {
   150→      ipcMain.removeHandler(channel);
   151→      ipcMain.removeAllListeners(channel);
   152→      this.registeredHandlers.delete(channel);
   153→    }
   154→  }
   155→
   156→  /* ---------------------------- Private ------------------------------*/
   157→
   158→  private register<Req, Res>(
   159→    channel: Channel,
   160→    handler: Handler<Req, Res>,
   161→  ): void {
   162→    if (this.registeredHandlers.has(channel)) {
   163→      throw new Error(`IPC handler already registered for ${channel}`);
   164→    }
   165→
   166→    const wrapped = async (event: IpcMainInvokeEvent, payload: Req) => {
   167→      try {
   168→        return await handler.call(this, event, payload);
   169→      } catch (err) {
   170→        console.error(`[IPC] Error in handler for ${channel}:`, err);
   171→        // Throwing serialises the error to renderer
   172→        throw err instanceof Error ? err : new Error(String(err));
   173→      }
   174→    };
   175→
   176→    ipcMain.handle(channel, wrapped);
   177→    this.registeredHandlers.set(channel, wrapped);
   178→  }
   179→
   180→  /** Register handlers contributed at runtime by plugins */
   181→  private dynamicRegister(
   182→    channel: string,
   183→    handler: (event: IpcMainInvokeEvent, payload: any) => any,
   184→  ): void {
   185→    if (this.registeredHandlers.has(channel as Channel)) {
   186→      throw new Error(`Channel ${channel} already taken`);
   187→    }
   188→    ipcMain.handle(channel, handler);
   189→    this.registeredHandlers.set(channel as Channel, handler);
   190→  }
   191→
   192→  /* ---------------------------- Handlers -----------------------------*/
   193→
   194→  private onSettingsGet: Handler<
   195→    SettingsGetRequest,
   196→    SettingsGetResponse
   197→  > = async (_evt, payload) => {
   198→    return payload.key
   199→      ? this.settings.get(payload.key)
   200→      : this.settings.getAll();
   201→  };
   202→
   203→  private onSettingsSet: Handler<
   204→    SettingsSetRequest,
   205→    SettingsSetResponse
   206→  > = async (_evt, { key, value }) => {
   207→    await this.settings.set(key, value);
   208→  };
   209→
   210→  private onAutoupdateCheck: Handler<undefined, AutoUpdateCheckResponse> =
   211→    async () => {
   212→      const update = await autoUpdater.checkForUpdates();
   213→      return update?.updateInfo?.version
   214→        ? { status: 'available', version: update.updateInfo.version }
   215→        : { status: 'up-to-date' };
   216→    };
   217→
   218→  private onCrashSubmit: Handler<
   219→    CrashSubmitRequest,
   220→    CrashSubmitResponse
   221→  > = async (_evt, { reason, details }) => {
   222→    const reportId = await this.crashReporter.submit(reason, details);
   223→    return { reportId };
   224→  };
   225→
   226→  private onWorkspaceExport: Handler<
   227→    WorkspaceExportRequest,
   228→    WorkspaceExportResponse
   229→  > = async (_evt, { workspaceId, format }) => {
   230→    const filePath = await this.workspaceExporter.export(workspaceId, format);
   231→    return { filePath };
   232→  };
   233→
   234→  private onWindowNew: Handler<WindowNewRequest, WindowNewResponse> = async (
   235→    _evt,
   236→    { workspaceId },
   237→  ) => {
   238→    const win = await this.windowManager.createWindow({ workspaceId });
   239→    return { windowId: win.id };
   240→  };
   241→
   242→  private onPluginInvoke: Handler<
   243→    PluginInvokeRequest,
   244→    PluginInvokeResponse
   245→  > = async (_evt, { pluginId, command, args }) => {
   246→    return await this.pluginService.invoke(pluginId, command, args);
   247→  };
   248→
   249→  /* ------------------------ Auto-update events -----------------------*/
   250→
   251→  private wireAutoupdateEvents(): void {
   252→    autoUpdater.on('checking-for-update', () => {
   253→      this.broadcast<AutoUpdateStateEvent>(Channels.AUTOUPDATE_STATE, {
   254→        phase: 'checking',
   255→      });
   256→    });
   257→
   258→    autoUpdater.on('download-progress', (progressObj) => {
   259→      this.broadcast<AutoUpdateStateEvent>(Channels.AUTOUPDATE_STATE, {
   260→        phase: 'downloading',
   261→        progress: progressObj.percent,
   262→      });
   263→    });
   264→
   265→    autoUpdater.on('update-downloaded', (info) => {
   266→      this.broadcast<AutoUpdateStateEvent>(Channels.AUTOUPDATE_STATE, {
   267→        phase: 'downloaded',
   268→        version: info.version,
   269→      });
   270→    });
   271→
   272→    autoUpdater.on('error', (err) => {
   273→      this.broadcast<AutoUpdateStateEvent>(Channels.AUTOUPDATE_STATE, {
   274→        phase: 'error',
   275→        reason: err.message,
   276→      });
   277→    });
   278→  }
   279→
   280→  /* --------------------------- Utilities -----------------------------*/
   281→
   282→  /**
   283→   * Broadcast an event to every open renderer.
   284→   */
   285→  private broadcast<T>(channel: Channel, payload: T): void {
   286→    BrowserWindow.getAllWindows().forEach((w) =>
   287→      w.webContents.send(channel, payload),
   288→    );
   289→  }
   290→
   291→  /**
   292→   * Send an event to a specific renderer WebContents if still alive.
   293→   */
   294→  private sendTo(webContents: WebContents, channel: Channel, payload: any): void {
   295→    if (!webContents.isDestroyed()) {
   296→      webContents.send(channel, payload);
   297→    }
   298→  }
   299→}
   300→
   301→/* -------------------------------------------------------------------------------------------------
   302→ * Bootstrap Helper
   303→ * -----------------------------------------------------------------------------------------------*/
   304→
   305→let registry: IpcRegistry | undefined;
   306→
   307→export function bootstrapIpcChannels(deps: {
   308→  settings: SettingsService;
   309→  crashReporter: CrashReporterService;
   310→  workspaceExporter: WorkspaceExportService;
   311→  pluginService: PluginService;
   312→  windowManager: WindowManager;
   313→}): void {
   314→  if (registry) {
   315→    throw new Error('IPC registry already initialised');
   316→  }
   317→  registry = new IpcRegistry(
   318→    deps.settings,
   319→    deps.crashReporter,
   320→    deps.workspaceExporter,
   321→    deps.pluginService,
   322→    deps.windowManager,
   323→  );
   324→  registry.initialise();
   325→}
   326→
   327→export function disposeIpcChannels(): void {
   328→  registry?.dispose();
   329→  registry = undefined;
   330→}
   331→```

