     2→/* PaletteFlow Studio — useViewModel Hook
     3→ *
     4→ * The renderer layer (“view”) should never talk to the domain layer directly.
     5→ * Instead, it consumes a View-Model object whose public API is *purely reactive*:
     6→ *
     7→ *     interface MyPanelVm {
     8→ *       readonly state: Readonly<MyPanelState>;
     9→ *       onChange(cb: () => void): () => void;  // subscribe/unsubscribe
    10→ *       dispose(): void;                       // free resources
    11→ *     }
    12→ *
    13→ * A View-Model is typically produced by an application-service or an IoC
    14→ * container that wires domain use-cases to presentation logic.  Because VM
    15→ * instances often maintain observables, async tasks, and plugin hooks, every
    16→ * React component that owns a VM should create it exactly once, re-render
    17→ * whenever it mutates, and tear it down on unmount.  This hook guarantees those
    18→ * invariants while staying concurrent-mode-safe (React 18+).
    19→ */
    20→
    21→import {
    22→  DependencyList,
    23→  useEffect,
    24→  useLayoutEffect,
    25→  useMemo,
    26→  useRef,
    27→  useSyncExternalStore,
    28→} from 'react';
    29→
    30→import { captureException } from '@/shared/crashReporter'; // renderer side Sentry wrapper
    31→import { log } from '@/shared/logger';                    // tiny winston wrapper
    32→
    33→/********************************************************************************
    34→ * Public Types
    35→ ******************************************************************************/
    36→
    37→/**
    38→ * The minimal contract a View-Model must fulfil to be consumable by this hook.
    39→ * The hook purposefully stays *very* small so that any state-management library
    40→ * (MobX, RxJS, XState, custom observables…) can be used underneath.
    41→ */
    42→export interface Disposable {
    43→  /**
    44→   * Release every resource that is *not* automatically GC’d:
    45→   *   – subscriptions to global event buses
    46→   *   – web-workers
    47→   *   – file handles
    48→   * DO NOT throw; merely *log*.
    49→   */
    50→  dispose(): void;
    51→}
    52→
    53→export interface Subscribable {
    54→  /**
    55→   * Register a listener called *after* the internal state changes.
    56→   * Must return an unsubscribe function.
    57→   */
    58→  onChange(listener: () => void): () => void;
    59→}
    60→
    61→/**
    62→ * Generic View-Model contract accepted by the hook.
    63→ */
    64→export type ViewModelLike<S = unknown> = Subscribable &
    65→  Disposable & {
    66→    /** Return a serialisable snapshot the UI can render without further tweaks. */
    67→    getState(): S;
    68→  };
    69→
    70→/**
    71→ * Options accepted by the hook.
    72→ */
    73→export interface UseViewModelOptions<S> {
    74→  /**
    75→   * Optional selector that derives a subset of the View-Model state.  Useful for
    76→   * trimming re-render scope or computing expensive projections only when the
    77→   * underlying data actually changed.
    78→   */
    79→  selector?: (state: S) => unknown;
    80→  /**
    81→   * Custom comparison used to decide if `selector(state)` changed.  Defaults to
    82→   * `Object.is`, which handles NaN, -0, +0 correctly.
    83→   */
    84→  equalityFn?: (a: unknown, b: unknown) => boolean;
    85→  /**
    86→   * Whether to dispose the View-Model *immediately* in `useLayoutEffect` (true)
    87→   * or in a passive `useEffect` (false).  The default (false) is often fine,
    88→   * but some tricky cases (e.g. DOM measurement) may need sync disposal.
    89→   */
    90→  syncDispose?: boolean;
    91→}
    92→
    93→/*******************************************************************************
    94→ * Hook Implementation
    95→ ******************************************************************************/
    96→
    97→/**
    98→ * Typed React hook that spins up any “View-Model-like” object, subscribes the
    99→ * component to its change events through the Concurrent-Mode-safe
   100→ * `useSyncExternalStore`, and disposes the VM on unmount.
   101→ *
   102→ * Usage:
   103→ *
   104→ *   const vm = useViewModel(() => new CanvasPanelVm(deps), [deps]);
   105→ *
   106→ *   // or with state projection:
   107→ *   const { nodes } = useViewModel(
   108→ *     () => new CanvasPanelVm(workspaceId),
   109→ *     [workspaceId],
   110→ *     { selector: (s) => ({ nodes: s.nodes }) }
   111→ *   );
   112→ */
   113→export function useViewModel<S = unknown, VM extends ViewModelLike<S> = ViewModelLike<S>>(
   114→  /**
   115→   * Factory producing a *fresh* View-Model.  It must be referentially-stable
   116→   * across renders, so pass it through `useCallback` if it captures props.
   117→   *
   118→   * IMPORTANT: The factory may throw.  We capture and re-throw after reporting
   119→   * to crash analytics so that the nearest ErrorBoundary handles UI recovery.
   120→   */
   121→  factory: () => VM,
   122→  /**
   123→   * Dependency list that determines when the VM should be recreated.  Follow
   124→   * the exact same rules as `useEffect`’s deps array.
   125→   */
   126→  deps: DependencyList = [],
   127→  /**
   128→   * Additional options.
   129→   */
   130→  options: UseViewModelOptions<S> = {},
   131→): VM {
   132→  const { selector, equalityFn = Object.is, syncDispose = false } = options;
   133→
   134→  /**
   135→   * The current View-Model instance.
   136→   * `useRef` is OK here because we handle lifecycle manually.
   137→   */
   138→  const vmRef = useRef<VM>();
   139→
   140→  /**
   141→   * Recreate the VM when dependencies change.
   142→   */
   143→  if (vmRef.current === undefined) {
   144→    try {
   145→      vmRef.current = factory();
   146→      if (!vmRef.current) {
   147→        throw new Error('ViewModel factory returned falsy value');
   148→      }
   149→    } catch (err) {
   150→      // Ensure crash analytics capture the context *before* React error boundary
   151→      captureException(err);
   152→      throw err; // Let UI layer handle gracefully
   153→    }
   154→  }
   155→
   156→  /**
   157→   * Compose a stable subscribe/getSnapshot pair required by
   158→   * `useSyncExternalStore`.
   159→   */
   160→  const getSnapshot = useMemo(() => {
   161→    const currentVm = vmRef.current!;
   162→    if (selector) {
   163→      let lastSelected = selector(currentVm.getState());
   164→      return () => {
   165→        const nextSelected = selector(currentVm.getState());
   166→        if (!equalityFn(lastSelected, nextSelected)) {
   167→          lastSelected = nextSelected;
   168→        }
   169→        return lastSelected;
   170→      };
   171→    }
   172→    // no selector; just return raw state
   173→    return () => currentVm.getState();
   174→  }, [selector, equalityFn, ...deps]); // must recompute when deps change
   175→
   176→  const subscribe = useMemo(() => {
   177→    const currentVm = vmRef.current!;
   178→    return (cb: () => void) => currentVm.onChange(cb);
   179→  }, deps); // recreate when VM replaced
   180→
   181→  /**
   182→   * `useSyncExternalStore` handles all
   183→   * – concurrency edge-cases
   184→   * – selective re-render
   185→   * – SSR (not used here but nice to have)
   186→   */
   187→  // eslint-disable-next-line react-hooks/rules-of-hooks
   188→  useSyncExternalStore(subscribe, getSnapshot);
   189→
   190→  /**
   191→   * Dispose logic mirror.  We cannot rely on garbage-collection because the VM
   192→   * may hold native handles or global event subscriptions.
   193→   */
   194→  const runDispose = () => {
   195→    const vm = vmRef.current;
   196→    if (vm) {
   197→      try {
   198→        vm.dispose();
   199→      } catch (err) {
   200→        // Disposal should never kill the app; just log
   201→        log.error(err, 'Error during ViewModel.dispose()');
   202→        captureException(err);
   203→      }
   204→      vmRef.current = undefined;
   205→    }
   206→  };
   207→
   208→  const useProperEffect = syncDispose ? useLayoutEffect : useEffect;
   209→
   210→  // eslint-disable-next-line react-hooks/rules-of-hooks
   211→  useProperEffect(() => {
   212→    // On deps change → VM was created earlier in render phase
   213→    return runDispose; // returned callback executes on unmount or deps change
   214→    // deps matches VM lifecycle:
   215→    // eslint-disable-next-line react-hooks/exhaustive-deps
   216→  }, deps);
   217→
   218→  return vmRef.current;
   219→}
   220→
   221→/*******************************************************************************
   222→ * Convenience Overload
   223→ ******************************************************************************/
   224→
   225→/**
   226→ * Overload when caller doesn’t care about selector/equalityFn.
   227→ */
   228→export function useViewModelSimple<S = unknown, VM extends ViewModelLike<S> = ViewModelLike<S>>(
   229→  factory: () => VM,
   230→  deps: DependencyList = [],
   231→): VM {
   232→  return useViewModel(factory, deps);
   233→}
