     2→/**************************************************************************************************
     3→ * PaletteFlow Studio
     4→ * File: core/domain/entities/Canvas.ts
     5→ *
     6→ * The Canvas aggregate root. A Canvas is an infinite work-area that owns Nodes and Links
     7→ * and can be themed.  It is a pure domain construct (framework-agnostic) and therefore
     8→ * carries no knowledge about persistence, UI, or infrastructure concerns.
     9→ **************************************************************************************************/
    10→
    11→// ──────────────────────────────────────────────────────────────────────────────────────────
    12→// Imports
    13→// ──────────────────────────────────────────────────────────────────────────────────────────
    14→import { UniqueEntityID } from '../value-objects/UniqueEntityID';
    15→import { Guard } from '../logic/Guard';
    16→import { DomainError } from '../errors/DomainError';
    17→import { DomainEventPublisher } from '../events/DomainEventPublisher';
    18→import { Node } from './Node';
    19→import { Link } from './Link';
    20→
    21→// ──────────────────────────────────────────────────────────────────────────────────────────
    22→// Events
    23→// ──────────────────────────────────────────────────────────────────────────────────────────
    24→
    25→/** Dispatched whenever a new node is added to the canvas. */
    26→export class NodeAddedToCanvas {
    27→  readonly occurredOn = new Date();
    28→  constructor(
    29→    public readonly canvasId: UniqueEntityID,
    30→    public readonly nodeId: UniqueEntityID
    31→  ) {}
    32→}
    33→
    34→/** Dispatched whenever a link is added to the canvas. */
    35→export class LinkCreatedOnCanvas {
    36→  readonly occurredOn = new Date();
    37→  constructor(
    38→    public readonly canvasId: UniqueEntityID,
    39→    public readonly linkId: UniqueEntityID
    40→  ) {}
    41→}
    42→
    43→/** Dispatched when the canvas metadata itself changes (title, theme, etc.). */
    44→export class CanvasModified {
    45→  readonly occurredOn = new Date();
    46→  constructor(public readonly canvasId: UniqueEntityID) {}
    47→}
    48→
    49→// ──────────────────────────────────────────────────────────────────────────────────────────
    50→// Aggregate Root
    51→// ──────────────────────────────────────────────────────────────────────────────────────────
    52→
    53→interface CanvasProps {
    54→  title: string;
    55→  themeId?: UniqueEntityID;
    56→  nodes?: Map<string, Node>;
    57→  links?: Map<string, Link>;
    58→  createdAt?: Date;
    59→  updatedAt?: Date;
    60→}
    61→
    62→/**
    63→ * Canvas aggregate root.
    64→ *
    65→ * Responsibilities:
    66→ *  • Own nodes & links
    67→ *  • Enforce invariants (no duplicate nodes, valid connections, etc.)
    68→ *  • Publish domain events
    69→ */
    70→export class Canvas {
    71→  // ── Factory ────────────────────────────────────────────────────────────────────────────
    72→  public static create(props: CanvasProps, id?: UniqueEntityID): Canvas {
    73→    const guard = Guard.againstNullOrUndefinedBulk([
    74→      { argument: props.title, argumentName: 'title' }
    75→    ]);
    76→    if (!guard.succeeded) {
    77→      throw new DomainError(guard.message);
    78→    }
    79→
    80→    return new Canvas(
    81→      {
    82→        title: props.title,
    83→        themeId: props.themeId,
    84→        nodes: props.nodes ?? new Map(),
    85→        links: props.links ?? new Map(),
    86→        createdAt: props.createdAt ?? new Date(),
    87→        updatedAt: props.updatedAt ?? new Date()
    88→      },
    89→      id ?? UniqueEntityID.create()
    90→    );
    91→  }
    92→
    93→  // ── Private Constructor ────────────────────────────────────────────────────────────────
    94→  private constructor(private props: CanvasProps, private readonly _id: UniqueEntityID) {
    95→    // invariant ‑ each link must connect nodes that actually exist on this canvas
    96→    for (const link of this.props.links!.values()) {
    97→      if (
    98→        !this.props.nodes!.has(link.sourceId.toString()) ||
    99→        !this.props.nodes!.has(link.targetId.toString())
   100→      ) {
   101→        throw new DomainError(
   102→          `Link (${link.id}) references nodes that are not part of the canvas.`
   103→        );
   104→      }
   105→    }
   106→  }
   107→
   108→  // ── Getters ────────────────────────────────────────────────────────────────────────────
   109→  get id(): UniqueEntityID {
   110→    return this._id;
   111→  }
   112→
   113→  get title(): string {
   114→    return this.props.title;
   115→  }
   116→
   117→  get themeId(): UniqueEntityID | undefined {
   118→    return this.props.themeId;
   119→  }
   120→
   121→  get createdAt(): Date {
   122→    return this.props.createdAt!;
   123→  }
   124→
   125→  get updatedAt(): Date {
   126→    return this.props.updatedAt!;
   127→  }
   128→
   129→  /** Returns a read-only snapshot of nodes. */
   130→  get nodes(): ReadonlyMap<string, Node> {
   131→    return new Map(this.props.nodes);
   132→  }
   133→
   134→  /** Returns a read-only snapshot of links. */
   135→  get links(): ReadonlyMap<string, Link> {
   136→    return new Map(this.props.links);
   137→  }
   138→
   139→  // ── Business Operations ────────────────────────────────────────────────────────────────
   140→
   141→  /** Mutates title (trimmed) and fires a `CanvasModified` event. */
   142→  rename(newTitle: string): void {
   143→    const trimmed = newTitle.trim();
   144→    if (!trimmed) {
   145→      throw new DomainError('Canvas title cannot be empty.');
   146→    }
   147→    if (trimmed === this.props.title) {
   148→      return; // no-op
   149→    }
   150→    this.props.title = trimmed;
   151→    this.touch();
   152→    DomainEventPublisher.publish(new CanvasModified(this.id));
   153→  }
   154→
   155→  /** Applies a theme to the canvas. */
   156→  applyTheme(themeId: UniqueEntityID): void {
   157→    if (this.props.themeId?.equals(themeId)) {
   158→      return; // already applied
   159→    }
   160→    this.props.themeId = themeId;
   161→    this.touch();
   162→    DomainEventPublisher.publish(new CanvasModified(this.id));
   163→  }
   164→
   165→  /** Adds (or replaces) a node. */
   166→  addNode(node: Node): void {
   167→    if (!node) {
   168→      throw new DomainError('Attempted to add an undefined node.');
   169→    }
   170→    this.props.nodes!.set(node.id.toString(), node);
   171→    this.touch();
   172→    DomainEventPublisher.publish(new NodeAddedToCanvas(this.id, node.id));
   173→  }
   174→
   175→  /** Removes a node and any links referencing it. */
   176→  removeNode(nodeId: UniqueEntityID): void {
   177→    const key = nodeId.toString();
   178→    if (!this.props.nodes!.has(key)) {
   179→      throw new DomainError(`Node (${key}) does not exist on this canvas.`);
   180→    }
   181→    this.props.nodes!.delete(key);
   182→
   183→    // Cascade delete links
   184→    for (const [linkId, link] of Array.from(this.props.links!.entries())) {
   185→      if (
   186→        link.sourceId.equals(nodeId) ||
   187→        link.targetId.equals(nodeId)
   188→      ) {
   189→        this.props.links!.delete(linkId);
   190→      }
   191→    }
   192→
   193→    this.touch();
   194→    DomainEventPublisher.publish(new CanvasModified(this.id));
   195→  }
   196→
   197→  /** Creates and stores a new link between two existing nodes. */
   198→  createLink(link: Link): void {
   199→    if (!this.props.nodes!.has(link.sourceId.toString())) {
   200→      throw new DomainError('Source node does not belong to this canvas.');
   201→    }
   202→    if (!this.props.nodes!.has(link.targetId.toString())) {
   203→      throw new DomainError('Target node does not belong to this canvas.');
   204→    }
   205→    this.props.links!.set(link.id.toString(), link);
   206→    this.touch();
   207→    DomainEventPublisher.publish(new LinkCreatedOnCanvas(this.id, link.id));
   208→  }
   209→
   210→  /** Removes a link from the canvas. */
   211→  removeLink(linkId: UniqueEntityID): void {
   212→    const key = linkId.toString();
   213→    if (!this.props.links!.has(key)) {
   214→      throw new DomainError(`Link (${key}) not found on canvas.`);
   215→    }
   216→    this.props.links!.delete(key);
   217→    this.touch();
   218→    DomainEventPublisher.publish(new CanvasModified(this.id));
   219→  }
   220→
   221→  // ── Persistence/Serialization ──────────────────────────────────────────────────────────
   222→  /** Serializes this aggregate into a plain JSON object safe for persistence. */
   223→  toJSON(): object {
   224→    return {
   225→      id: this.id.toString(),
   226→      title: this.title,
   227→      themeId: this.themeId?.toString() ?? null,
   228→      nodes: Array.from(this.props.nodes!.values()).map((n) => n.toJSON()),
   229→      links: Array.from(this.props.links!.values()).map((l) => l.toJSON()),
   230→      createdAt: this.createdAt.toISOString(),
   231→      updatedAt: this.updatedAt.toISOString()
   232→    };
   233→  }
   234→
   235→  /** Updates the `updatedAt` timestamp. */
   236→  private touch(): void {
   237→    this.props.updatedAt = new Date();
   238→  }
   239→}
   240→```
