     6→ *  The IpcMainManager wires Electron’s ipcMain to the rest of the application core in a
     7→ *  cohesive, safe-by-default way.  All main-process <-> renderer traffic MUST pass through
     8→ *  this class so that:
     9→ *    •  Every message is typed, validated, and logged
    10→ *    •  Domain-layer use-cases stay framework-agnostic
    11→ *    •  We retain a single place to harden against malformed/hostile renderer input
    12→ *
    13→ *  NOTE: Never invoke ipcMain.on / ipcMain.handle outside of this file.
    14→ ********************************************************************************************************************/
    15→
    16→import { BrowserWindow, IpcMainEvent, IpcMainInvokeEvent, ipcMain } from 'electron';
    17→import { autoUpdater } from 'electron-updater';
    18→
    19→import { ILogger } from '../logging/ILogger';
    20→import { CrashReporter } from '../crash/CrashReporter';
    21→import { SettingsService } from '../settings/SettingsService';
    22→import { WindowRegistry } from '../windows/WindowRegistry';
    23→import { PluginBridge } from '../plugins/PluginBridge';
    24→
    25→// Domain use-cases (thin proxies to the application core)
    26→import { CreateNode } from '../../core/usecases/CreateNode';
    27→import { ApplyTheme } from '../../core/usecases/ApplyTheme';
    28→import { ExportWorkspace } from '../../core/usecases/ExportWorkspace';
    29→
    30→/**
    31→ * IPC channels are stringly typed; to reduce error-proneness we maintain a strongly-typed
    32→ * map of well-known channels here.  Plugin channels are dynamically added at runtime.
    33→ */
    34→export const IPC_CHANNELS = {
    35→    // Renderer lifecycle
    36→    RENDERER_READY: 'renderer:ready',
    37→    // Workspace
    38→    CREATE_NODE: 'workspace:create-node',
    39→    EXPORT_WORKSPACE: 'workspace:export',
    40→    APPLY_THEME: 'workspace:apply-theme',
    41→    // Settings
    42→    SETTINGS_GET: 'settings:get',
    43→    SETTINGS_SET: 'settings:set',
    44→    // Auto-updates
    45→    CHECK_FOR_UPDATES: 'app:check-for-updates',
    46→    // Crash / analytics
    47→    TRACK_EVENT: 'analytics:track-event',
    48→    // Plugin passthrough
    49→    PLUGIN_MESSAGE: 'plugin:message',
    50→} as const;
    51→
    52→export type IpcChannel = typeof IPC_CHANNELS[keyof typeof IPC_CHANNELS];
    53→
    54→/**
    55→ *  Utility: coerces an unknown renderer payload into a given runtime guard.
    56→ */
    57→function assert<T>(
    58→    guard: (value: unknown) => value is T,
    59→    value: unknown,
    60→    errMessage: string,
    61→): T {
    62→    if (!guard(value)) {
    63→        throw new Error(errMessage);
    64→    }
    65→    return value;
    66→}
    67→
    68→export interface IpcMainManagerDependencies {
    69→    logger: ILogger;
    70→    windowRegistry: WindowRegistry;
    71→    settings: SettingsService;
    72→    crashReporter: CrashReporter;
    73→    pluginBridge: PluginBridge;
    74→    createNode: CreateNode;
    75→    applyTheme: ApplyTheme;
    76→    exportWorkspace: ExportWorkspace;
    77→}
    78→
    79→/**
    80→ *  Central registry for all ipcMain listeners.
    81→ */
    82→export class IpcMainManager {
    83→    private readonly log: ILogger;
    84→    private readonly deps: IpcMainManagerDependencies;
    85→
    86→    /** Keep track of added listeners for clean shutdown / hot reload */
    87→    private readonly registeredListeners: Array<{
    88→        channel: IpcChannel | string;
    89→        type: 'on' | 'handle';
    90→        listener: (...args: any[]) => void | Promise<void>;
    91→    }> = [];
    92→
    93→    constructor(deps: IpcMainManagerDependencies) {
    94→        this.deps = deps;
    95→        this.log = deps.logger.child({ scope: 'IpcMainManager' });
    96→    }
    97→
    98→    /**
    99→     *  Initializes all core IPC handlers and wires plugin-contributed ones.
   100→     */
   101→    public initialize(): void {
   102→        this.log.info('Initializing IPC main listeners …');
   103→
   104→        /* -------------------------------------------------------------
   105→         *  Renderer lifecycle
   106→         * ----------------------------------------------------------- */
   107→        this.on(IPC_CHANNELS.RENDERER_READY, this.handleRendererReady.bind(this));
   108→
   109→        /* -------------------------------------------------------------
   110→         *  Workspace / domain use-cases
   111→         * ----------------------------------------------------------- */
   112→        this.handle(IPC_CHANNELS.CREATE_NODE, this.handleCreateNode.bind(this));
   113→        this.handle(IPC_CHANNELS.EXPORT_WORKSPACE, this.handleExportWorkspace.bind(this));
   114→        this.handle(IPC_CHANNELS.APPLY_THEME, this.handleApplyTheme.bind(this));
   115→
   116→        /* -------------------------------------------------------------
   117→         *  Settings
   118→         * ----------------------------------------------------------- */
   119→        this.handle(IPC_CHANNELS.SETTINGS_GET, this.handleSettingsGet.bind(this));
   120→        this.handle(IPC_CHANNELS.SETTINGS_SET, this.handleSettingsSet.bind(this));
   121→
   122→        /* -------------------------------------------------------------
   123→         *  Auto-updates
   124→         * ----------------------------------------------------------- */
   125→        this.handle(IPC_CHANNELS.CHECK_FOR_UPDATES, this.handleCheckForUpdates.bind(this));
   126→
   127→        /* -------------------------------------------------------------
   128→         *  Crash analytics
   129→         * ----------------------------------------------------------- */
   130→        this.on(IPC_CHANNELS.TRACK_EVENT, this.handleTrackEvent.bind(this));
   131→
   132→        /* -------------------------------------------------------------
   133→         *  Plugin passthrough
   134→         * ----------------------------------------------------------- */
   135→        this.on(IPC_CHANNELS.PLUGIN_MESSAGE, this.handlePluginMessage.bind(this));
   136→
   137→        this.log.info(`IPC initialization complete. Registered ${this.registeredListeners.length} listener(s).`);
   138→    }
   139→
   140→    /**
   141→     *  Cleanly removes all listeners.  Useful during hot-reload or when running tests.
   142→     */
   143→    public dispose(): void {
   144→        for (const { channel, type, listener } of this.registeredListeners) {
   145→            try {
   146→                if (type === 'on') {
   147→                    ipcMain.removeListener(channel, listener);
   148→                } else {
   149→                    // ipcMain.handle wraps a listener on the internal map; .removeHandler is idempotent
   150→                    ipcMain.removeHandler(channel);
   151→                }
   152→                this.log.debug(`Unregistered IPC listener '${channel}'.`);
   153→            } catch (err) {
   154→                this.log.error(err, `Failed to unregister listener '${channel}'.`);
   155→            }
   156→        }
   157→        this.registeredListeners.length = 0;
   158→    }
   159→
   160→    /* ****************************************************************************************************************
   161→     *  Helper registration methods
   162→     **************************************************************************************************************** */
   163→
   164→    private on(channel: IpcChannel | string, listener: (event: IpcMainEvent, ...args: any[]) => void) {
   165→        ipcMain.on(channel, listener);
   166→        this.registeredListeners.push({ channel, listener, type: 'on' });
   167→    }
   168→
   169→    private handle(
   170→        channel: IpcChannel | string,
   171→        listener: (event: IpcMainInvokeEvent, ...args: any[]) => Promise<unknown>,
   172→    ) {
   173→        ipcMain.handle(channel, listener);
   174→        this.registeredListeners.push({ channel, listener, type: 'handle' });
   175→    }
   176→
   177→    /* ****************************************************************************************************************
   178→     *  IPC Handlers
   179→     **************************************************************************************************************** */
   180→
   181→    // --------------------------------- Renderer lifecycle ----------------------------------------------------------
   182→
   183→    private handleRendererReady(event: IpcMainEvent): void {
   184→        const window = BrowserWindow.fromWebContents(event.sender);
   185→        this.log.info({ id: window?.id }, 'Renderer signaled readiness.');
   186→    }
   187→
   188→    // --------------------------------- Workspace use-cases --------------------------------------------------------
   189→
   190→    private async handleCreateNode(event: IpcMainInvokeEvent, payload: unknown): Promise<string> {
   191→        try {
   192→            const { workspaceId, type, initialContent } = assert<
   193→                { workspaceId: string; type: string; initialContent?: unknown }
   194→            >(
   195→                (v): v is { workspaceId: string; type: string; initialContent?: unknown } =>
   196→                    typeof v === 'object' &&
   197→                    v !== null &&
   198→                    typeof (v as any).workspaceId === 'string' &&
   199→                    typeof (v as any).type === 'string',
   200→                payload,
   201→                'Invalid payload for CREATE_NODE',
   202→            );
   203→
   204→            const nodeId = await this.deps.createNode.execute({
   205→                workspaceId,
   206→                nodeType: type,
   207→                initialContent,
   208→            });
   209→
   210→            this.log.info({ nodeId, workspaceId }, 'Node created via IPC.');
   211→            return nodeId;
   212→        } catch (err) {
   213→            this.handleError(event, err, 'Failed to create node');
   214→            throw err; // rethrow so renderer gets rejection
   215→        }
   216→    }
   217→
   218→    private async handleExportWorkspace(event: IpcMainInvokeEvent, payload: unknown): Promise<string> {
   219→        try {
   220→            const { workspaceId, format } = assert<{ workspaceId: string; format: string }>(
   221→                (v): v is { workspaceId: string; format: string } =>
   222→                    typeof v === 'object' &&
   223→                    v !== null &&
   224→                    typeof (v as any).workspaceId === 'string' &&
   225→                    typeof (v as any).format === 'string',
   226→                payload,
   227→                'Invalid payload for EXPORT_WORKSPACE',
   228→            );
   229→
   230→            const filePath = await this.deps.exportWorkspace.execute({ workspaceId, format });
   231→            this.log.info({ workspaceId, filePath }, 'Workspace exported via IPC.');
   232→
   233→            return filePath;
   234→        } catch (err) {
   235→            this.handleError(event, err, 'Failed to export workspace');
   236→            throw err;
   237→        }
   238→    }
   239→
   240→    private async handleApplyTheme(event: IpcMainInvokeEvent, payload: unknown): Promise<void> {
   241→        try {
   242→            const { themeId } = assert<{ themeId: string }>(
   243→                (v): v is { themeId: string } =>
   244→                    typeof v === 'object' && v !== null && typeof (v as any).themeId === 'string',
   245→                payload,
   246→                'Invalid payload for APPLY_THEME',
   247→            );
   248→
   249→            await this.deps.applyTheme.execute({ themeId });
   250→            this.log.info({ themeId }, 'Theme applied via IPC.');
   251→        } catch (err) {
   252→            this.handleError(event, err, 'Failed to apply theme');
   253→            throw err;
   254→        }
   255→    }
   256→
   257→    // --------------------------------- Settings --------------------------------------------------------------------
   258→
   259→    private async handleSettingsGet(): Promise<Record<string, unknown>> {
   260→        try {
   261→            return this.deps.settings.getAll();
   262→        } catch (err) {
   263→            this.log.error(err, 'Failed to retrieve settings');
   264→            throw err;
   265→        }
   266→    }
   267→
   268→    private async handleSettingsSet(
   269→        _event: IpcMainInvokeEvent,
   270→        kv: unknown,
   271→    ): Promise<Record<string, unknown>> {
   272→        try {
   273→            const data = assert<Record<string, unknown>>(
   274→                (v): v is Record<string, unknown> => typeof v === 'object' && v !== null,
   275→                kv,
   276→                'Invalid payload for SETTINGS_SET',
   277→            );
   278→
   279→            const updated = await this.deps.settings.setMany(data);
   280→            this.log.info({ updatedKeys: Object.keys(data) }, 'Settings updated via IPC.');
   281→            return updated;
   282→        } catch (err) {
   283→            this.log.error(err, 'Failed to update settings via IPC.');
   284→            throw err;
   285→        }
   286→    }
   287→
   288→    // --------------------------------- Auto-updates ----------------------------------------------------------------
   289→
   290→    private async handleCheckForUpdates(): Promise<void> {
   291→        try {
   292→            await autoUpdater.checkForUpdates();
   293→            this.log.info('Manual update check triggered via IPC.');
   294→        } catch (err) {
   295→            this.log.error(err, 'Failed to check for updates via IPC.');
   296→            throw err;
   297→        }
   298→    }
   299→
   300→    // --------------------------------- Crash / analytics -----------------------------------------------------------
   301→
   302→    private handleTrackEvent(_event: IpcMainEvent, payload: unknown): void {
   303→        try {
   304→            const { category, action, label, value } = assert<
   305→                { category: string; action: string; label?: string; value?: number }
   306→            >(
   307→                (v): v is { category: string; action: string; label?: string; value?: number } =>
   308→                    typeof v === 'object' &&
   309→                    v !== null &&
   310→                    typeof (v as any).category === 'string' &&
   311→                    typeof (v as any).action === 'string',
   312→                payload,
   313→                'Invalid payload for TRACK_EVENT',
   314→            );
   315→
   316→            this.deps.crashReporter.captureBreadcrumb({
   317→                category,
   318→                message: `${action}${label ? ` (${label})` : ''}`,
   319→                data: { value },
   320→            });
   321→        } catch (err) {
   322→            this.log.warn(err, 'Malformed analytics event ignored.');
   323→        }
   324→    }
   325→
   326→    // --------------------------------- Plugin messages -------------------------------------------------------------
   327→
   328→    private handlePluginMessage(event: IpcMainEvent, payload: unknown): void {
   329→        try {
   330→            const msg = assert<
   331→                {
   332→                    pluginId: string;
   333→                    event: string;
   334→                    data?: unknown;
   335→                }
   336→            >(
   337→                (v): v is { pluginId: string; event: string; data?: unknown } =>
   338→                    typeof v === 'object' &&
   339→                    v !== null &&
   340→                    typeof (v as any).pluginId === 'string' &&
   341→                    typeof (v as any).event === 'string',
   342→                payload,
   343→                'Invalid payload for PLUGIN_MESSAGE',
   344→            );
   345→
   346→            this.deps.pluginBridge.emitToPlugin(msg.pluginId, msg.event, msg.data);
   347→            this.log.debug({ pluginId: msg.pluginId, event: msg.event }, 'Routed plugin IPC message.');
   348→        } catch (err) {
   349→            this.handleError(event, err, 'Failed to route plugin message');
   350→        }
   351→    }
   352→
   353→    /* ****************************************************************************************************************
   354→     *  Helpers
   355→     **************************************************************************************************************** */
   356→
   357→    private handleError(event: IpcMainEvent | IpcMainInvokeEvent, err: unknown, userMessage: string) {
   358→        this.log.error(err, userMessage);
   359→
   360→        const window = BrowserWindow.fromWebContents(event.sender);
   361→        if (!window?.isDestroyed()) {
   362→            // Send a safe, non-technical message back to renderer so it can surface a toast
   363→            window.webContents.send('app:error', { message: userMessage });
   364→        }
   365→
   366→        // Enrich crash reporter
   367→        this.deps.crashReporter.captureException(err as Error, { hint: userMessage });
   368→    }
   369→}
