     2→/**
     3→ * PaletteFlow Studio – DependencyContainer
     4→ *
     5→ * This file wires together the dependency-injection graph that is used by the
     6→ * renderer process.  We build on top of `tsyringe`, a lightweight, reflection-
     7→ * free container that plays nicely with tree-shaking and supports Electron
     8→ * hot-reload scenarios out of the box.
     9→ *
    10→ * NOTE:
    11→ *   Every service or state store that needs to be shared across React/Preact
    12→ *   components, view-models or IPC handlers should be registered here.  Keep
    13→ *   this file lean—**never** import heavy domain logic directly; instead import
    14→ *   thin façade classes (use-cases, stores, helpers) so that we don’t bloat the
    15→ *   renderer bundle.
    16→ */
    17→
    18→import {
    19→  container as rootContainer,
    20→  DependencyContainer as TsyringeContainer,
    21→  InjectionToken,
    22→  Lifecycle,
    23→  delay,
    24→} from 'tsyringe';
    25→import { ipcRenderer, IpcRendererEvent } from 'electron';
    26→
    27→// We purposefully import *types* only here (they’ll be erased at compile time)
    28→import type { CanvasStore } from '../view-model/CanvasStore';
    29→import type { WorkspaceStore } from '../view-model/WorkspaceStore';
    30→import type { ThemeStore } from '../view-model/ThemeStore';
    31→import type { CommandRegistry } from '../../shared/commands/CommandRegistry';
    32→import type { PluginRegistry } from '../../shared/plugins/PluginRegistry';
    33→import type { SettingsService } from '../../shared/settings/SettingsService';
    34→import type { AnalyticsService } from '../../shared/analytics/AnalyticsService';
    35→
    36→/* -------------------------------------------------------------------------- */
    37→/*                             Injection Tokens                               */
    38→/* -------------------------------------------------------------------------- */
    39→
    40→/**
    41→ * Using Symbols instead of strings prevents clashes when plugins register their
    42→ * own services.
    43→ */
    44→export const TOKENS = {
    45→  CanvasStore: Symbol.for('CanvasStore'),
    46→  WorkspaceStore: Symbol.for('WorkspaceStore'),
    47→  ThemeStore: Symbol.for('ThemeStore'),
    48→  CommandRegistry: Symbol.for('CommandRegistry'),
    49→  PluginRegistry: Symbol.for('PluginRegistry'),
    50→  SettingsService: Symbol.for('SettingsService'),
    51→  AnalyticsService: Symbol.for('AnalyticsService'),
    52→} as const;
    53→
    54→/* -------------------------------------------------------------------------- */
    55→/*                      Conditional (lazy) dependency load                    */
    56→/* -------------------------------------------------------------------------- */
    57→
    58→/**
    59→ * Because some services are dynamically imported (to cut initial bundle size),
    60→ * we expose helper factories.  They return promises so that consumers can
    61→ * `await container.resolveAsync(TOKENS.X)`.
    62→ */
    63→const factories = {
    64→  async CanvasStore(): Promise<CanvasStore> {
    65→    const { CanvasStoreImpl } = await import('../view-model/CanvasStore');
    66→    return new CanvasStoreImpl();
    67→  },
    68→  async WorkspaceStore(): Promise<WorkspaceStore> {
    69→    const { WorkspaceStoreImpl } = await import('../view-model/WorkspaceStore');
    70→    return new WorkspaceStoreImpl();
    71→  },
    72→  async ThemeStore(): Promise<ThemeStore> {
