   134→      useFactory: delay(() => factories.CanvasStore()),
   135→      lifecycle: Lifecycle.Singleton,
   136→    });
   137→    this._container.register(TOKENS.WorkspaceStore, {
   138→      useFactory: delay(() => factories.WorkspaceStore()),
   139→      lifecycle: Lifecycle.Singleton,
   140→    });
   141→    this._container.register(TOKENS.ThemeStore, {
   142→      useFactory: delay(() => factories.ThemeStore()),
   143→      lifecycle: Lifecycle.Singleton,
   144→    });
   145→
   146→    // Command & Plugin registries
   147→    this._container.register(TOKENS.CommandRegistry, {
   148→      useFactory: delay(() => factories.CommandRegistry()),
   149→      lifecycle: Lifecycle.Singleton,
   150→    });
   151→    this._container.register(TOKENS.PluginRegistry, {
   152→      useFactory: delay(() => factories.PluginRegistry()),
   153→      lifecycle: Lifecycle.Singleton,
   154→    });
   155→
   156→    // Listen for IPC events that require DI look-ups (e.g., issued by main process)
   157→    this.installIpcBridge();
   158→
   159→    if (import.meta.env?.DEV) {
   160→      (globalThis as any)[globalKey] = this._container;
   161→    }
   162→  }
   163→
   164→  /**
   165→   * Resolve a dependency synchronously.  Throws if the container has not been
   166→   * initialised or if the token is async-only.
   167→   */
   168→  public static resolve<T>(token: InjectionToken<T>): T {
   169→    if (!this._container) {
   170→      throw new Error('DependencyContainer not initialised – call init() first.');
   171→    }
   172→    return this._container.resolve(token);
   173→  }
   174→
   175→  /**
   176→   * Resolve an async factory-registered dependency.
   177→   */
   178→  public static async resolveAsync<T>(token: InjectionToken<T>): Promise<T> {
   179→    if (!this._container) {
   180→      throw new Error('DependencyContainer not initialised – call init() first.');
   181→    }
   182→    return await this._container.resolve<Promise<T>>(token);
   183→  }
   184→
   185→  /**
   186→   * Allows plugins to register their own services at runtime.
   187→   */
   188→  public static registerSingleton<T>(
   189→    token: InjectionToken<T>,
   190→    ctor: new (...args: never[]) => T,
   191→  ): void {
   192→    if (!this._container) {
   193→      throw new Error('DependencyContainer not initialised – call init() first.');
   194→    }
