   196→    if (this._container.isRegistered(token)) {
   197→      console.warn(
   198→        `[DI] Token ${token.toString()} already registered – plugin override ignored.`,
   199→      );
   200→      return;
   201→    }
   202→
   203→    this._container.registerSingleton<T>(token, ctor);
   204→  }
   205→
   206→  /**
   207→   * For testing & hot-reload only – wipes the current container.
   208→   */
   209→  public static reset(): void {
   210→    this._container = null;
   211→  }
   212→
   213→  /* ------------------------------------------------------------------------ */
   214→  /*                              IPC Integration                             */
   215→  /* ------------------------------------------------------------------------ */
   216→
   217→  /**
   218→   * Expose a minimal IPC bridge so that the main process can request
   219→   * information held only in the renderer (e.g., unsaved changes indicator).
   220→   */
   221→  private static installIpcBridge(): void {
   222→    ipcRenderer.on('pfstudio:get-state', async (event: IpcRendererEvent, token: string) => {
   223→      try {
   224→        // eslint-disable-next-line @typescript-eslint/await-thenable
   225→        const instance = await this.resolveAsync<any>(Symbol.for(token));
   226→        event.reply(`pfstudio:get-state:response:${token}`, { ok: true, payload: instance });
   227→      } catch (err) {
   228→        console.error('[IPC Bridge] Failed to resolve token', token, err);
   229→        event.reply(`pfstudio:get-state:response:${token}`, {
   230→          ok: false,
   231→          error: (err as Error).message,
   232→        });
   233→      }
   234→    });
   235→  }
   236→}
