     2→/**
     3→ * PaletteFlow Studio – Event Bus Contract & Reference Implementation
     4→ * ---------------------------------------------------------------
     5→ * The core application layer communicates exclusively through
     6→ * domain events.  To stay framework-agnostic, we define our own
     7→ * minimal contract here, together with a robust in-memory
     8→ * implementation that is good enough for unit tests and
     9→ * low-throughput production scenarios (e.g. CLI adapters).
    10→ *
    11→ * NOTE:   UI adapters (Electron windows, plugin host, etc.) swap
    12→ *         this implementation for an RxJS / IPC hybrid, but that
    13→ *         lives in the infrastructure layer and must not be
    14→ *         imported by core code.
    15→ */
    16→
    17→import { v4 as uuid } from 'uuid';
    18→
    19→/* ------------------------------------------------------------------
    20→ * Domain primitives
    21→ * ------------------------------------------------------------------ */
    22→
    23→/**
    24→ * A domain event is an immutable fact that something business-relevant
    25→ * happened at a specific time.  The `type` field SHOULD be a unique
    26→ * reverse-DNS string (e.g. "studio.node.created") so that plugins can
    27→ * safely filter/extend without name collisions.
    28→ */
    29→export interface DomainEvent<TPayload = unknown> {
    30→  /** Unique, reverse-DNS event name (e.g. "studio.node.created") */
    31→  readonly type: string;
    32→
    33→  /** ISO timestamp of when the event occurred */
    34→  readonly occurredAt: string;
    35→
    36→  /** Opaque correlation ID that ties events with the same cause */
    37→  readonly correlationId?: string;
    38→
    39→  /** Business-specific payload */
    40→  readonly payload: TPayload;
    41→}
    42→
    43→/**
    44→ * Convenience factory for ad-hoc events without adding ceremony.
    45→ * (Useful for tests or infrastructure adapters.)
    46→ */
    47→export function createEvent<TPayload = unknown>(
    48→  type: string,
    49→  payload: TPayload,
    50→  correlationId?: string,
    51→): DomainEvent<TPayload> {
    52→  return {
    53→    type,
    54→    payload,
    55→    correlationId,
    56→    occurredAt: new Date().toISOString(),
    57→  };
    58→}
    59→
    60→/* ------------------------------------------------------------------
    61→ * Event Bus contract
    62→ * ------------------------------------------------------------------ */
    63→
    64→/**
    65→ * Signature for event handlers.  Handlers MAY return a promise;
    66→ * failures will be captured and forwarded to the bus logger.
    67→ */
    68→export type EventHandler<E extends DomainEvent = DomainEvent> = (
    69→  event: E,
    70→) => void | Promise<void>;
    71→
    72→export interface Subscription {
    73→  /** Opaque ID that can be used to unsubscribe programmatically */
    74→  readonly id: string;
    75→
    76→  /** Cancels the underlying handler */
    77→  unsubscribe(): void;
    78→}
    79→
    80→/**
    81→ * Options that influence how an event is dispatched.
    82→ */
    83→export interface PublishOptions {
    84→  /**
    85→   * If `true`, events will be delivered synchronously in the caller’s
    86→   * call stack.  This is handy for tests but **must** be `false` in any
    87→   * user-facing UI thread to avoid jank / re-entrance bugs.
    88→   *
    89→   * Defaults to `false`.
    90→   */
    91→  readonly sync?: boolean;
    92→}
    93→
    94→/**
    95→ * Clean-Architecture friendly abstraction that decouples all layers
    96→ * from any specific eventing library (EventEmitter, RxJS, etc.).
    97→ */
    98→export interface IEventBus {
    99→  /**
   100→   * Broadcast a single event to all interested handlers.
   101→   */
   102→  publish<E extends DomainEvent>(
   103→    event: E,
   104→    options?: PublishOptions,
   105→  ): Promise<void>;
   106→
   107→  /**
   108→   * Publish multiple events atomically.  An implementation MAY ensure
   109→   * transactional guarantees (e.g. either all or none are dispatched),
   110→   * but the default in-memory variant does **not**.
   111→   */
   112→  publishAll(events: ReadonlyArray<DomainEvent>, options?: PublishOptions): Promise<void>;
   113→
   114→  /**
   115→   * Register a new handler for the given event type.
   116→   *
   117→   * eventType may be:
   118→   *   • a concrete string
   119→   *   • the wildcard "*" for all events
   120→   */
   121→  subscribe<E extends DomainEvent>(
   122→    eventType: string,
   123→    handler: EventHandler<E>,
   124→  ): Subscription;
   125→
   126→  /**
   127→   * Convenience helper to run a handler only once.  The subscription
   128→   * self-destructs after the first invocation.
   129→   */
   130→  once<E extends DomainEvent>(
   131→    eventType: string,
   132→    handler: EventHandler<E>,
   133→  ): Subscription;
   134→
   135→  /**
   136→   * Remove a previously registered subscription.
   137→   */
   138→  unsubscribe(subscriptionId: string): void;
   139→
   140→  /**
   141→   * Removes all handlers – handy for test tear-down or hot-module reloads.
   142→   */
   143→  drain(): void;
   144→}
   145→
   146→/* ------------------------------------------------------------------
   147→ * Reference implementation – In-Memory, Single-Process
   148→ * ------------------------------------------------------------------ */
   149→
   150→export class InMemoryEventBus implements IEventBus {
   151→  private readonly handlers: Map<
   152→    string, // eventType
   153→    Map<string, EventHandler> // subscriptionId -> handler
   154→  > = new Map();
   155→
   156→  private readonly logger: Pick<Console, 'debug' | 'error'>;
   157→
   158→  constructor(logger: Pick<Console, 'debug' | 'error'> = console) {
   159→    this.logger = logger;
   160→  }
   161→
   162→  /* ---------------------------------- publish ---------------------------------- */
   163→
   164→  async publish<E extends DomainEvent>(
   165→    event: E,
   166→    options: PublishOptions = {},
   167→  ): Promise<void> {
   168→    await this.dispatch([event], options);
   169→  }
   170→
   171→  async publishAll(
   172→    events: ReadonlyArray<DomainEvent>,
   173→    options: PublishOptions = {},
   174→  ): Promise<void> {
   175→    await this.dispatch(events, options);
   176→  }
   177→
   178→  /* -------------------------------- subscribe --------------------------------- */
   179→
   180→  subscribe<E extends DomainEvent>(
   181→    eventType: string,
   182→    handler: EventHandler<E>,
   183→  ): Subscription {
   184→    if (!eventType) {
   185→      throw new Error('eventType must be a non-empty string');
   186→    }
   187→    if (typeof handler !== 'function') {
   188→      throw new Error('handler must be a function');
   189→    }
   190→
   191→    const subscriptionId = uuid();
   192→
   193→    if (!this.handlers.has(eventType)) {
   194→      this.handlers.set(eventType, new Map());
   195→    }
   196→    this.handlers.get(eventType)!.set(subscriptionId, handler);
   197→
   198→    return {
   199→      id: subscriptionId,
   200→      unsubscribe: () => this.unsubscribe(subscriptionId),
   201→    };
   202→  }
   203→
   204→  once<E extends DomainEvent>(
   205→    eventType: string,
   206→    handler: EventHandler<E>,
   207→  ): Subscription {
   208→    const wrapper: EventHandler<E> = async (event: E) => {
   209→      try {
   210→        await handler(event);
   211→      } finally {
   212→        sub.unsubscribe();
   213→      }
   214→    };
   215→
   216→    const sub = this.subscribe(eventType, wrapper);
   217→    return sub;
   218→  }
   219→
   220→  /* ------------------------------ unsubscribe ---------------------------------- */
   221→
   222→  unsubscribe(subscriptionId: string): void {
   223→    for (const [, subs] of this.handlers) {
   224→      if (subs.delete(subscriptionId)) {
   225→        return;
   226→      }
   227→    }
   228→  }
   229→
   230→  drain(): void {
   231→    this.handlers.clear();
   232→  }
   233→
   234→  /* ------------------------------------------------------------------ helpers */
   235→
   236→  private async dispatch(
   237→    events: ReadonlyArray<DomainEvent>,
   238→    { sync = false }: PublishOptions,
   239→  ) {
   240→    const deliveries: Promise<void>[] = [];
   241→
   242→    for (const event of events) {
   243→      this.logger.debug('[EventBus] Dispatching', event.type, event);
   244→      const matchedHandlers = [
   245→        ...(this.handlers.get('*')?.values() ?? []),
   246→        ...(this.handlers.get(event.type)?.values() ?? []),
   247→      ];
   248→
   249→      for (const handler of matchedHandlers) {
   250→        const invoke = () =>
   251→          Promise.resolve()
   252→            .then(() => handler(event))
   253→            .catch((err) => {
   254→              this.logger.error(
   255→                `[EventBus] Handler threw for event "${event.type}"`,
   256→                err,
   257→              );
   258→            });
   259→
   260→        if (sync) {
   261→          // Execute immediately (still async to allow error capturing)
   262→          deliveries.push(invoke());
   263→        } else {
   264→          // Defer so we never block the caller
   265→          deliveries.push(queueMicrotaskPolyfill(invoke));
   266→        }
   267→      }
   268→    }
   269→
   270→    await Promise.all(deliveries);
   271→  }
   272→}
   273→
   274→/**
   275→ * queueMicrotask is not available in all Node versions that our
   276→ * CLI adapters support.  We polyfill with setTimeout(…, 0) while
   277→ * preserving the Promise-based contract.
   278→ */
   279→function queueMicrotaskPolyfill(fn: () => void): Promise<void> {
   280→  return new Promise<void>((resolve) =>
   281→    // eslint-disable-next-line prefer-arrow-callback
   282→    (typeof queueMicrotask === 'function'
   283→      ? queueMicrotask
   284→      : (cb: () => void) => setTimeout(cb, 0))(async () => {
   285→        try {
   286→          await fn();
   287→        } finally {
   288→          resolve();
   289→        }
   290→      }),
   291→  );
   292→}
