     node.moveTo(pluginDisposition.x, pluginDisposition.y);
     await this.nodeRepo.save(node);
     await this.eventBus.publish(new NodePositionUpdated({...}));
   });
   ```
7. **Invokes post-move plugin hooks**

#### Step 6: Domain Entity Mutation
Location: `src/core/domain/entities/Node.ts:220-229`
```typescript
public moveTo(position: Vector2D): this {
  if (Number.isNaN(position.x) || Number.isNaN(position.y)) {
    throw new Error('Position must contain valid numbers.');
  }
  this._position = { x: position.x, y: position.y };
  this._touch();
