  ) {}

  async execute(dto: UpdateNodePositionDTO): Promise<Result<UpdateNodePositionError, void>> {
    // 1. Fetch current state with version
    const [node, serverVersion] = await this.nodeRepo.findByIdWithVersion(dto.nodeId);

    // 2. Check for version conflict
    if (dto.baseVersion !== serverVersion) {
      const resolution = await this.conflictResolver.resolve({
        localOperation: { type: 'move', position: { x: dto.x, y: dto.y } },
        remoteState: node,
        strategy: 'operational-transform' // or 'crdt', 'last-write-wins'
      });

      if (resolution.rejected) {
        return err(new UpdateNodePositionError(
          UpdateNodePositionErrorKind.CONFLICT_REJECTED
        ));
      }

      // Apply transformed operation
      dto = { ...dto, ...resolution.transformed };
    }

    // 3. Continue with existing logic...
  }
}
```

### 4.3 Recommended Conflict Resolution Approach

Given the application's characteristics (rich node content, spatial positioning, user creativity focus), I recommend:

**Hybrid Approach: CRDTs for Position + OT for Content**

1. **Node Positions (CRDTs)**: Use Last-Writer-Wins Registers (LWW-Register) for `x`, `y` coordinates. Spatial conflicts can resolve cleanly to the most recent position.

2. **Text/Code Content (OT)**: For text-based nodes (Markdown, Code), use Operational Transformation to merge concurrent edits without data loss.

3. **Structural Changes (Intent Preservation)**: For adding/removing nodes and links, use intent-based resolution:
   - Two users adding nodes → both succeed (no conflict)
   - User A deletes node while User B edits it → preserve edit, mark node as "deleted by A"

4. **Plugin Data (Application-Specific)**: Provide hooks for plugins to define their own merge strategies for custom metadata.

